def get_data_infor():
    i = 0
    cur = ""
    file = csv.reader(open("./Final_Augmented_dataset_Diseases_and_Symptoms.csv"))
    next(file)
    for v in file:
        if(v[0] != cur):
            print(f"{(cur, i)},")
            cur = v[0]
            i = 1
        else:
            i += 1
        
def create_data():
    file = csv.reader(open("./data/Final_Augmented_dataset_Diseases_and_Symptoms.csv"))
    training = csv.writer(open("./data/training_data.csv", "w", newline="\n"))
    test = csv.writer(open("./data/test_data.csv", "w", newline="\n"))

    header = next(file)
    training.writerow(header)
    test.writerow(header)

    for _, size, _ in data_info:
        k = math.floor(0.8*size)
        for _ in range(k):
            training.writerow(next(file))
        for _ in range(k, size):
            test.writerow(next(file))

def get_symptoms_list():
    file = csv.reader(open("./Final_Augmented_dataset_Diseases_and_Symptoms.csv"))
    symptoms = next(file)
    for s in symptoms:
        print(f"(\"{s}\", \" \", 0.0),")
    
def get_training_size():
    training = csv.reader(open("./data/training_data.csv"))
    i = 0
    next(training)
    for _ in training:
        i += 1
    return i

def get_test_size():
    test = csv.reader(open("./data/test_data.csv"))
    i = 0
    next(test)
    for _ in test:
        i += 1
    return i

def init_logistic_weight_json():
    w = [ {"weight" : [ [0.0] for _ in range(377) ], "bias" : 0.0} for _ in range(len(data_info)) ]
    with open("./weight.json", "w") as file:
        json.dump(w, file, indent=4)

def init_softmax_weight_json():
    w = {
        "weight" : [ [0.0 for _ in range(377)] for _ in range(772)] , 
        "bias" : [ [0.0] for _ in range(772)]
    }
    with open("./data/softmax_new_weight.json", "w") as file:
        json.dump(w, file, indent=4)

def get_class_weight():
    res = []
    
    for (_, v, _) in data_info:
        res.append(2/math.sqrt(v))
    print(res)

